mapper.insert:
INSERT INTO seckill_orders (
    order_no, user_id, product_id, order_amount, status
) VALUES (
    #{orderNo}, #{userId}, #{productId}, #{orderAmount}, #{status}
)

mapper.select:
SELECT order_no, user_id, product_id, order_amount, status, created_at, updated_at
FROM seckill_orders
WHERE order_no = #{orderNo}

SELECT order_no, user_id, product_id, order_amount, status, created_at, updated_at
FROM seckill_orders
WHERE user_id = #{userId}
  AND product_id = #{productId}
LIMIT 1
